$(document).ready(function(){$("body").on("click",".ipCheckBtn",function(){var c=$(this).data("id");$.ajax({url:"/reviews/check_ip/"+c,dataType:"json",success:function(i,n){!0===i.ipWarningsFound?($("#ipSuccess"+c).hide(),$("#ipWarning"+c).show()):($("#ipSuccess"+c).show(),$("#ipWarning"+c).hide())}})})});